const count = wwLib.variables.get('cartCount');
const withTax = count * 1.05;
return `cartCount=${count}, withTax=${withTax.toFixed(2)}`;

const current = wwLib.variables.get('cartCount') ?? 0;
wwLib.variables.set('cartCount', current + 1);
return current + 1;

try {
  const r = await fetch('https://api.github.com/repos/facebook/react');
  if (!r.ok) throw new Error('HTTP ' + r.status);
  const json = await r.json();
  return { ok: true, stars: json.stargazers_count, name: json.full_name };
} catch (err) {
  return { ok: false, error: String(err && err.message || err) };
}

try {
  await wwLib.collections.refetch('Featured Products');
} catch (err) {
  // collection may not exist in this build — keep going so the demo always finishes
}
const stamp = new Date().toISOString();
wwLib.variables.set('lastSyncAt', stamp);
wwLib.variables.set('jsSyncStatus', `synced @ ${stamp}`);
return { syncedAt: stamp };

const next = (wwLib.variables.get('processedCount') ?? 0) + 1;
wwLib.variables.set('processedCount', next);
