config.code:
if (!wwLib.variables.get('userEmail')) {
  wwLib.variables.set('userEmail', '');
}
return true;

wwLib.variables.set('jsNavStatus', 'navigating to /home?from=js');
await wwLib.navigate.to({ path: '/home', queryParams: { from: 'js' } });
return 'navigated to /home';

wwLib.variables.set('jsNavStatus', 'opened example.com in new tab');
await wwLib.navigate.to({ linkType: 'external', externalUrl: 'https://example.com', newTab: true });
return 'opened external';

wwLib.variables.set('jsNavStatus', 'going back');
await wwLib.navigate.prev('/javascript-test');
return 'back';

// Manipulate a *local* array variable as a stand-in for a datasource.
// Demonstrates the same shape wwLib.collections.update would use against a real one.
const items = (wwLib.variables.get('productItems') ?? []).slice();
const nextId = `p${items.length + 1}`;
items.push({ id: nextId, name: `Hat ${nextId}`, price: 12.34 });
wwLib.variables.set('productItems', items);
wwLib.variables.set('jsCollectionRowCount', items.length);
return { added: nextId, total: items.length };

try {
  await wwLib.collections.refetch('Featured Products');
  wwLib.variables.set('jsCollectionRowCount', (wwLib.variables.get('productItems') ?? []).length);
  return 'refetched';
} catch (err) {
  return 'no datasource: ' + String(err);
}

// Demo emit: writes a string instead of dispatching to a real instance,
// since the example page does not embed a shared component instance.
wwLib.variables.set('jsComponentResult', `emit('demoTrigger', { at: ${Date.now()} })`);
return 'emitted';

const ids = (wwLib.variables.get('jsSharedAddedIds') ?? []).slice();
const id = `dyn-${ids.length + 1}-${Date.now().toString(36)}`;
ids.push(id);
wwLib.variables.set('jsSharedAddedIds', ids);
return { added: id, total: ids.length };

const current = wwLib.variables.get('jsPopoverState');
wwLib.variables.set('jsPopoverState', current === 'open' ? 'closed' : 'open');
return wwLib.variables.get('jsPopoverState');

wwLib.variables.set('jsFormName', '');
wwLib.variables.set('jsFormState', '(reset)');
return 'reset';

// Demo-only: simulate a successful login without hitting a real endpoint.
const user = { id: 'u-42', email: 'demo@example.com' };
wwLib.variables.set('jsAuthEmail', user.email);
return { ok: true, user };

const user = { id: 'u-99', email: 'override@example.com' };
wwLib.variables.set('jsAuthEmail', user.email);
return user;

const text = `hello from wwLib @ ${new Date().toISOString()}`;
try {
  await wwLib.clipboard.copy(text);
  wwLib.variables.set('jsBrowserStatus', `copied: ${text}`);
} catch (err) {
  wwLib.variables.set('jsBrowserStatus', 'copy failed: ' + String(err));
}
return text;

try {
  await wwLib.files.download('https://www.w3.org/WAI/ER/tests/xhtml/testfiles/resources/pdf/dummy.pdf', 'dummy.pdf');
  wwLib.variables.set('jsBrowserStatus', 'download triggered');
} catch (err) {
  wwLib.variables.set('jsBrowserStatus', 'download failed: ' + String(err));
}
return 'ok';

// Tiny 1x1 transparent PNG
const pngB64 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=';
try {
  const url = await wwLib.files.fromBase64(pngB64, 'image/png', 'pixel.png');
  wwLib.variables.set('jsB64Url', typeof url === 'string' ? url : 'data:image/png;base64,' + pngB64);
  wwLib.variables.set('jsBrowserStatus', 'created data URL');
} catch (err) {
  wwLib.variables.set('jsBrowserStatus', 'fromBase64 failed: ' + String(err));
}
return 'ok';

try {
  await wwLib.scroll.to('jsTopAnchor', { behavior: 'smooth' });
  wwLib.variables.set('jsBrowserStatus', 'scrolled to top anchor');
} catch (err) {
  // Fall back to native window scroll if no element by id is registered.
  if (typeof window !== 'undefined') window.scrollTo({ top: 0, behavior: 'smooth' });
  wwLib.variables.set('jsBrowserStatus', 'scrolled (native fallback)');
}
return 'ok';

try {
  await wwLib.print.pdf({ filename: 'js-demo.pdf' });
  wwLib.variables.set('jsBrowserStatus', 'print dialog opened');
} catch (err) {
  wwLib.variables.set('jsBrowserStatus', 'pdf failed: ' + String(err));
}
return 'ok';

wwLib.variables.set('jsDelayStatus', 'sleeping 800ms…');
try {
  await wwLib.timing.delay(800);
} catch (err) {
  // Fallback if the underlying timeDelay step isn't available.
  await new Promise((r) => setTimeout(r, 800));
}
wwLib.variables.set('jsDelayStatus', 'awake');
return 'awake';

try {
  await wwLib.event.stopPropagation();
} catch (err) {
  // Some renderers may not bubble events through the workflow runtime —
  // we still want the demo to record the click.
}
const next = (wwLib.variables.get('jsInnerClickCount') ?? 0) + 1;
wwLib.variables.set('jsInnerClickCount', next);
return next;

const next = (wwLib.variables.get('jsOuterClickCount') ?? 0) + 1;
wwLib.variables.set('jsOuterClickCount', next);
return next;

// Drive a real existing workflow as a subroutine, observe its return.
const before = wwLib.variables.get('cartCount') ?? 0;
let returned;
try {
  returned = await wwLib.workflows.run('jsDemoIncrementCart');
} catch (err) {
  returned = 'sub-workflow error: ' + String(err);
}
const after = wwLib.variables.get('cartCount') ?? 0;
const summary = `before=${before}, after=${after}, returned=${JSON.stringify(returned)}`;
wwLib.variables.set('jsWorkflowReturn', summary);
return summary;

const raw = wwLib.variables.get('jsEscapeHatchInput') ?? '';
let step;
try { step = JSON.parse(raw); } catch (err) {
  wwLib.variables.set('jsEscapeHatchResult', 'invalid JSON: ' + String(err));
  return null;
}
try {
  const out = await wwLib.actions.run(step);
  wwLib.variables.set('jsEscapeHatchResult', `ran ${step.type}: ${JSON.stringify(out) ?? 'ok'}`);
  return out;
} catch (err) {
  wwLib.variables.set('jsEscapeHatchResult', 'failed: ' + String(err && err.message || err));
  return null;
}
